query technicianAvailableTimesForMultipleServices($nailServices: [String!]!, $bookingDate: Date!, $existingNailService: [String!], $existingBookingDateTime: DateTime) {
  technicianAvailableTimesForMultipleServices(input: {
    nailServices: $nailServices,
    bookingDate: $bookingDate,
    existingNailService: $existingNailService,
    existingBookingDateTime: $existingBookingDateTime
  }) {
    technician {
      id
      nickname
    }
    availableTimes
    bookedTimes
  }
}
